2000	// altura [y_min, y_max]) sobrepõe a CollisionAABB 'box'. O teste é decomposto
2001	// em (1) overlap do intervalo vertical e (2) distância do centro do círculo
2002	// (projeção do cilindro no plano XZ) ao retângulo formado pela AABB em XZ.
2003	bool CylinderIntersectsAABB(glm::vec2 pos_xz, float raio, float y_min, float y_max, const CollisionAABB& box)
2004	{
2005	    // Overlap no eixo vertical (Y)
2006	    if (y_max < box.min.y || y_min > box.max.y)
2007	        return false;
2008	
2009	    // Ponto do retângulo (projeção da AABB em XZ) mais próximo do centro do círculo
2010	    float closest_x = glm::clamp(pos_xz.x, box.min.x, box.max.x);
2011	    float closest_z = glm::clamp(pos_xz.y, box.min.z, box.max.z);
2012	
2013	    float dx = pos_xz.x - closest_x;
2014	    float dz = pos_xz.y - closest_z;
2015	
2016	    return (dx*dx + dz*dz) < (raio * raio);
2017	}
2018	
2019	bool CylinderIntersectsLine(glm::vec2 pos_xz, float raio, float y_min_jogador, float y_max_jogador, const CollisionLine& line)
2020	{
2021	    // 1. Testa o overlap no eixo vertical (Y)
2022	    if (y_max_jogador < line.y_min || y_min_jogador > line.y_max)
2023	        return false;
2024	
2025	    // 2. Matemática vetorial no plano XZ
2026	    glm::vec2 ab = line.p2 - line.p1;       // Vetor da parede
2027	    glm::vec2 ap = pos_xz - line.p1;        // Vetor do início da parede até o jogador
2028	
2029	    // Calcula a projeção escalar de AP sobre AB
2030	    float proj = glm::dot(ap, ab);
2031	    float ab_len_sq = glm::dot(ab, ab);     // Comprimento da parede ao quadrado
2032	    
2033	    // Calcula 't', que é a porcentagem da projeção ao longo da parede
2034	    float t = proj / ab_len_sq;
2035	    
2036	    // Grampeia 't' entre 0 e 1 para garantir que não estamos checando um ponto além da parede
2037	    t = glm::clamp(t, 0.0f, 1.0f);
2038	
2039	    // Encontra a coordenada exata do ponto mais próximo na parede
2040	    glm::vec2 closest_point = line.p1 + t * ab;
2041	    
2042	    // Calcula a distância do jogador até esse ponto
2043	    glm::vec2 distance_vec = pos_xz - closest_point;
2044	    
2045	    // Se a distância ao quadrado for menor que o raio ao quadrado, é colisão!
2046	    return glm::dot(distance_vec, distance_vec) < (raio * raio);
2047	}
