2049	// Testa se o cilindro do jogador, na posição candidata 'pos' (mesma referência
2050	// de Pos_Player — não os pés diretamente, ver PLAYER_FEET_Y_OFFSET), colide
2051	// com alguma AABB do cenário registrada em g_CollisionAABBs.
2052	//
2053	// O intervalo vertical testado é "encolhido" por COLLISION_SKIN em cada ponta:
2054	// sem isso, ao ficar exatamente apoiado no chão (pés tocando o topo da AABB do
2055	// piso) o teste consideraria o jogador permanentemente colidindo também na
2056	// horizontal, travando todo o movimento. Esse encolhimento permite uma
2057	// penetração tolerável de poucos centímetros, imperceptível no jogo.
2058	bool PlayerCollidesAt(const glm::vec3& pos)
2059	{
2060	    glm::vec2 pos_xz(pos.x, pos.z);
2061	    float feet_y = pos.y + PLAYER_FEET_Y_OFFSET;
2062	    float y_min = feet_y + COLLISION_SKIN;
2063	    float y_max = feet_y + g_PlayerCollider.altura - COLLISION_SKIN;
2064	
2065	    // Testa colisões com caixas estáticas (cenário)
2066	    for (const CollisionAABB& box : g_CollisionAABBs)
2067	    {
2068	        if (CylinderIntersectsAABB(pos_xz, g_PlayerCollider.raio, y_min, y_max, box))
2069	            return true;
2070	    }
2071	
2072	    // Testa colisões com paredes diagonais
2073	    for (const CollisionLine& line : g_CollisionLines) {
2074	        if (CylinderIntersectsLine(pos_xz, g_PlayerCollider.raio, y_min, y_max, line))
2075	            return true;
2076	    }
2077	
2078	    // Testa colisão dinâmica com a PORTA FECHADA
2079	    if (!g_IsButtonPressed) {
2080	        if (CylinderIntersectsAABB(pos_xz, g_PlayerCollider.raio, y_min, y_max, g_ClosedDoorAABB))
2081	            return true;
2082	    }
2083	
2084	    // Testa colisão dinâmica com a CAIXA
2085	    // O jogador só esbarra na caixa se NÃO estiver segurando ela
2086	    if (!g_IsHoldingBox) 
2087	    {
2088	        // Cria a matriz do cubo exatamente onde ele está no mundo agora
2089	        glm::mat4 model_cube = Matrix_Translate(g_BoxPosition.x, g_BoxPosition.y, g_BoxPosition.z) 
2090	                            * Matrix_Rotate_Y(g_BoxAngleY) 
2091	                            * Matrix_Scale(1.0f/8.0f, 1.0f/8.0f, 1.0f/8.0f);
2092	    
2093	        // Calcula a AABB da caixa naquele exato frame
2094	        CollisionAABB boxAABB = ComputeWorldAABB(
2095	            g_VirtualScene["Cube"].bbox_min, 
2096	            g_VirtualScene["Cube"].bbox_max, 
2097	            model_cube
2098	        );
2099	        
2100	        // Testa se o cilindro do jogador bateu nessa AABB gerada
2101	        if (CylinderIntersectsAABB(pos_xz, g_PlayerCollider.raio, y_min, y_max, boxAABB))
2102	            return true;    
2103	    }
2104	
2105	    // Testa colisão dinâmica com o RÁDIO
2106	    if (!g_IsHoldingRadio) 
2107	    {
2108	        // Matriz do rádio baseada em sua escala visual (1/9)
2109	        glm::mat4 model_radio = Matrix_Translate(g_RadioPosition.x, g_RadioPosition.y, g_RadioPosition.z) 
2110	                              * Matrix_Rotate_Y(g_RadioAngleY) 
2111	                              * Matrix_Scale(1.0f/9.0f, 1.0f/9.0f, 1.0f/9.0f);
2112	    
2113	        // Calcula a AABB usando as bounding boxes locais carregadas pelo tinyobj (usando a malha "Shell" como referência)
2114	        CollisionAABB radioAABB = ComputeWorldAABB(
2115	            g_VirtualScene["Shell"].bbox_min, 
2116	            g_VirtualScene["Shell"].bbox_max, 
2117	            model_radio
2118	        );
2119	        
2120	        if (CylinderIntersectsAABB(pos_xz, g_PlayerCollider.raio, y_min, y_max, radioAABB))
2121	            return true;    
2122	    }
2123	
2124	    return false;
2125	}
