2157	            max_box.z > g_ClosedDoorAABB.min.z && min_box.z < g_ClosedDoorAABB.max.z) 
2158	        {
2159	            return true;
2160	        }
2161	    }
2162	
2163	    // Testa colisão dinâmica contra o RÁDIO
2164	    // Usa os mesmos tamanhos que você configurou no RadioCollidesAt
2165	    float r_xz = 0.15f; 
2166	    float r_y  = 0.22f; 
2167	    glm::vec3 min_radio = g_RadioPosition + glm::vec3(-r_xz, -r_y, -r_xz);
2168	    glm::vec3 max_radio = g_RadioPosition + glm::vec3(r_xz, r_y, r_xz);
2169	
2170	    // Se a AABB da caixa sobrepor a AABB do rádio, é colisão!
2171	    if (max_box.x > min_radio.x && min_box.x < max_radio.x &&
2172	        max_box.y > min_radio.y && min_box.y < max_radio.y &&
2173	        max_box.z > min_radio.z && min_box.z < max_radio.z) 
