2349	// Preenche g_CollisionAABBs com as AABBs de mundo do cenário estático contra
2350	// o qual o jogador colide: paredes/chão/teto das duas salas (definidas
2351	// manualmente, já que a geometria é simples e alinhada aos eixos) mais o
2352	// cubo e o botão (cuja AABB local é transformada pela matriz "model" usada ao
2353	// desenhá-los). Chamada uma única vez, no setup, pois o cenário é estático.
2354	void SetupCollisionAABBs()
2355	{
2356	    g_CollisionAABBs.clear();
2357	    g_CollisionLines.clear();
2358	
2359	    // Espessura "fake" usada para dar volume às paredes/chão/teto no teste de colisão
2360	    const float wall_t = 0.1f;
2361	
2362	    // Limites das salas (x,z) e altura (y), conforme mapeamento da cena
2363	    const float sala1_min = -4.0f, sala1_max = 4.0f;
2364	    const float sala2_min = 4.2f,  sala2_max = 12.0f;
2365	    float s3_xmin = 6.0f, s3_xmax = 10.0f;
2366	    float s3_zmin = 6.2f, s3_zmax = 10.1f;
2367	    const float y_min = -1.0f, y_max = 3.0f;
2368	
2369	    // A porta entre a Sala 1 e a Sala 2 (centrada em Z = 0)
2370	    const float porta_z = 0.0f;
2371	    // A nova porta no final da Sala 2 (centrada em X = 8.0)
2372	    const float porta2_x = 8.0f; 
2373	    
2374	    const float porta_meia_largura = 0.6f; 
2375	    const float porta_topo_y = 0.5f;      
2376	
2377	    // Cria uma laje retangular de parede (AABB)
2378	    auto add_wall_slab = [&](float x_lo, float x_hi, float z_lo, float z_hi, float y_lo, float y_hi)
2379	    {
2380	        if (z_lo < z_hi && x_lo < x_hi)
2381	            g_CollisionAABBs.push_back({ glm::vec3(x_lo, y_lo, z_lo), glm::vec3(x_hi, y_hi, z_hi) });
2382	    };
2383	
2384	    // Corta um buraco em uma parede que corre paralela ao eixo Z
2385	    auto add_wall_with_doorway = [&](float x_lo, float x_hi, float z_lo, float z_hi)
2386	    {
2387	        add_wall_slab(x_lo, x_hi, z_lo, porta_z - porta_meia_largura, y_min, y_max);
2388	        add_wall_slab(x_lo, x_hi, porta_z + porta_meia_largura, z_hi, y_min, y_max);
2389	        add_wall_slab(x_lo, x_hi, porta_z - porta_meia_largura, porta_z + porta_meia_largura, porta_topo_y, y_max);
2390	    };
2391	
2392	    // Corta um buraco em uma parede que corre paralela ao eixo X (NOVO)
2393	    auto add_wall_with_doorway_z = [&](float x_lo, float x_hi, float z_lo, float z_hi)
2394	    {
2395	        add_wall_slab(x_lo, porta2_x - porta_meia_largura, z_lo, z_hi, y_min, y_max);
2396	        add_wall_slab(porta2_x + porta_meia_largura, x_hi, z_lo, z_hi, y_min, y_max);
2397	        add_wall_slab(porta2_x - porta_meia_largura, porta2_x + porta_meia_largura, z_lo, z_hi, porta_topo_y, y_max);
2398	    };
2399	
2400	    // Constrói a sala inteira. Adicionamos o parâmetro 'porta_em_z_max' com valor padrão 'false'.
2401	    auto add_room_aabbs = [&](float x_min, float x_max, float z_min, float z_max, bool porta_em_x_min, bool porta_em_x_max, bool porta_em_z_max = false)
2402	    {
2403	        // Chão e teto
2404	        add_wall_slab(x_min - wall_t, x_max + wall_t, z_min - wall_t, z_max + wall_t, y_min - wall_t, y_min);
2405	        add_wall_slab(x_min - wall_t, x_max + wall_t, z_min - wall_t, z_max + wall_t, y_max, y_max + wall_t);
2406	
2407	        // Parede em x = x_min
2408	        if (porta_em_x_min)
2409	            add_wall_with_doorway(x_min - wall_t, x_min, z_min - wall_t, z_max + wall_t);
2410	        else
2411	            add_wall_slab(x_min - wall_t, x_min, z_min - wall_t, z_max + wall_t, y_min, y_max);
2412	
2413	        // Parede em x = x_max
2414	        if (porta_em_x_max)
2415	            add_wall_with_doorway(x_max, x_max + wall_t, z_min - wall_t, z_max + wall_t);
