2462	    // Parede de vidro em z=+1
2463	    g_CollisionAABBs.push_back({ glm::vec3(-1.0f, y_min, 1.0f - wall_t), glm::vec3(1.0f, y_max, 1.0f + wall_t) });
2464	    // Parede de vidro em z=-1
2465	    g_CollisionAABBs.push_back({ glm::vec3(-1.0f, y_min, -1.0f - wall_t), glm::vec3(1.0f, y_max, -1.0f + wall_t) });
2466	
2467	    // Botão: mesma matriz "model" usada para desenhá-lo (Matrix_Translate(9,-1,-1) * Matrix_Scale(1.65,1.65,1.65))
2468	    glm::mat4 model_button = Matrix_Translate(9.0f, -1.0f, -1.0f) * Matrix_Scale(1.65f, 1.65f, 1.65f);
2469	    g_CollisionAABBs.push_back(ComputeWorldAABB(g_VirtualScene["portal_button_reduced_2"].bbox_min, g_VirtualScene["portal_button_reduced_2"].bbox_max, model_button));
2470	
2471	    // Paredes Diagonais:
2472	    // Parede diagonal da Sala 2 (Centro: 11.0, -2.7 | Rotação: -45 graus | Escala: 2.0)
2473	    // Calculamos as extremidades aplicando o seno/cosseno de 45 graus (0.707) * escala (2.0) = 1.414
2474	    float offsetX = 1.414f;
2475	    float offsetZ = 1.414f;
2476	    
2477	    g_CollisionLines.push_back({
2478	        glm::vec2(11.0f - offsetX, -2.7f - offsetZ), // Ponto 1 (~ 9.586, -4.114)
2479	        glm::vec2(11.0f + offsetX, -2.7f + offsetZ), // Ponto 2 (~ 12.414, -1.286)
2480	        y_min,                                       // Chão (-1.0f)
2481	        y_max                                        // Teto (3.0f)
2482	    });
2483	
2484	    // Hitbox dinâmica da porta 2 (Fechada)
2485	    // Usamos 3.14159265f no lugar de M_PI pois a macro foi definida dentro do main
2486	    glm::mat4 model_door_closed = Matrix_Translate(8.0f, -1.0f, 6.1f) 
2487	                                * Matrix_Rotate_Y(3.14159265f) 
2488	                                * Matrix_Scale(1.5f, 1.5f, 1.5f);
2489	                                
2490	    g_ClosedDoorAABB = ComputeWorldAABB(
2491	        g_VirtualScene["portal_door_combined_model_1"].bbox_min, 
