2563	// Função que carrega uma imagem para ser utilizada como textura
2564	// Vincula às unidades de textura 0 (difusa) e 1 (auxiliar) as texturas usadas
2565	// pelo objeto identificado por object_id, conforme o mapeamento do
2566	// shader_fragment.glsl. Objetos de cor sólida (sem textura) deixam as unidades
2567	// sem textura vinculada. Necessário porque o macOS limita o fragment shader a
2568	// 16 samplers (veja comentário em LoadTextureImage()).
2569	void BindTexturesForObject(GLint object_id)
2570	{
2571	    int diffuse = -1; // índice em g_TextureID da textura difusa
2572	    int aux     = -1; // índice da textura auxiliar (especular/metalness/emissivo)
2573	
2574	    switch (object_id)
2575	    {
2576	        case WALL: case WALL_2: case WALL_4: case DOOR_WALL: diffuse = 1;  break;
2577	        case FLOOR:                                          diffuse = 18; break;
2578	        case CEILING:                                        diffuse = 19; break;
2579	        case PLAYER_HEAD:                                    diffuse = 2;  break;
2580	        case PLAYER_EYE:                                     diffuse = 3;  break;
2581	        case PLAYER_TORSO:                                   diffuse = 4;  break;
2582	        case PLAYER_LEGS:                                    diffuse = 5;  break;
2583	        case PLAYER_HAIR:                                    diffuse = 6;  break;
2584	        case CUBE_003:                          diffuse = 8;  aux = 11; break;
2585	        case CUBE:                              diffuse = 9;  aux = 12; break;
2586	        case CUBE_CIRCLE3:                                   diffuse = 7;  break;
2587	        case BUTTON: case BUTTON_001:                        diffuse = 14; break;
2588	        case DOOR:                                           diffuse = 17; break;
2589	        case SEC_CAM:                           diffuse = 20; aux = 21; break;
2590	        case RADIO_SHELL:                                    diffuse = 22; break;
2591	        case RADIO_MAIN:                        diffuse = 23; aux = 0;  break;
2592	        case RADIO_GRID:                                     diffuse = 24; break;
2593	        case RADIO_SCREEN:                      diffuse = 25; aux = 31; break;
2594	        case RADIO_LIGHT:                                    diffuse = 26; break;
2595	        case RADIO_ANTENNA:                                  diffuse = 27; break;
2596	        case RADIO_BUTTON:                                   diffuse = 28; break;
2597	        case RADIO_BUTTON_RIFLED:                            diffuse = 29; break;
2598	        case RADIO_BASE_PART:                                diffuse = 30; break;
2599	        case CAKE:                                           diffuse = 13; break;
2600	        case CAKE_CANDLE:                                    diffuse = 15; break;
2601	        default: break; // objetos de cor sólida não amostram textura
2602	    }
2603	
2604	    // Para objetos sem textura (cor sólida) ou sem mapa auxiliar, vinculamos
2605	    // mesmo assim uma textura válida de fallback (a primeira carregada). Essas
2606	    // unidades não são amostradas nessas branches do shader, mas isso evita o
2607	    // aviso do driver do macOS "using zero texture because texture unloadable".
2608	    GLuint fallbackTex = (g_NumLoadedTextures > 0) ? g_TextureID[0] : 0;
2609	    GLuint fallbackSmp = (g_NumLoadedTextures > 0) ? g_SamplerID[0] : 0;
2610	
2611	    glActiveTexture(GL_TEXTURE0);
2612	    glBindTexture(GL_TEXTURE_2D, diffuse >= 0 ? g_TextureID[diffuse] : fallbackTex);
2613	    glBindSampler(0, diffuse >= 0 ? g_SamplerID[diffuse] : fallbackSmp);
2614	
2615	    glActiveTexture(GL_TEXTURE1);
2616	    glBindTexture(GL_TEXTURE_2D, aux >= 0 ? g_TextureID[aux] : fallbackTex);
2617	    glBindSampler(1, aux >= 0 ? g_SamplerID[aux] : fallbackSmp);
2618	}
